import { createAgent } from 'mastra';
import { VexMiddleware } from '@vex_dev/sdk';

const vex = new VexMiddleware({
  projectId: 'your-vex-project-id',
  rules: ['healthcare-phi-deid']
});

const triageAgent = createAgent({
  name: 'triage',
  workflow: {
    steps: [
      {
        id: 'intake',
        tools: ['ehr-lookup'],
        middleware: [vex.deidentifyPhi()]
      },
      {
        id: 'assessment',
        llm: 'gpt-4',
        middleware: [vex.validateOutput()]
      }
    ]
  }
});

import { Tool } from 'mastra';
import { VexSchemaValidator } from '@vex_dev/sdk';

const ehrLookupTool: Tool = {
  name: 'ehr-lookup',
  schema: {
    patientId: 'string',
    fields: ['vitals', 'meds', 'allergies']
  },
  execute: async (input) => {
    const rawEhrData = await fetchEhr(input);

    // Vex validates EHR response schema
    const validatedData = await VexSchemaValidator({
      schemaId: 'healthcare-ehr-vitals',
      data: rawEhrData,
      context: { patientId: input.patientId }
    });

    return validatedData;
  }
};

import { createWorkflow } from 'mastra';
import { VexAuditLogger } from '@vex_dev/sdk';

const logger = new VexAuditLogger({
  auditTrail: true,
  retention: '7y',
  format: 'fda-part11'
});

const clinicalWorkflow = createWorkflow({
  name: 'clinical-decision',
  steps: [
    {
      id: 'diagnosis',
      llm: 'gpt-4-medical',
      middleware: [logger.recordDecision()]
    },
    {
      id: 'treatment',
      tools: ['drug-interaction'],
      middleware: [logger.recordRationale()]
    }
  ],
  globalMiddleware: [logger.auditTrail()]
});
